fn scheduler_context_ok(source: &str, token_present: bool) -> bool {
    source.eq_ignore_ascii_case("novovmctl") && token_present
}

fn manual_route_env_hits_from_lookup<F>(has_value: F) -> Vec<&'static str>
where
    F: Fn(&str) -> bool,
{
    MANUAL_ROUTE_ENV_LOCK_KEYS
        .iter()
        .copied()
        .filter(|k| has_value(k))
        .collect()
}

#[cfg(test)]
#[test]
fn scheduler_gate_matrix_invalid_source_fails() {
    assert!(!scheduler_context_ok("manual", true));
}

#[cfg(test)]
#[test]
fn scheduler_gate_matrix_missing_token_fails() {
    assert!(!scheduler_context_ok("novovmctl", false));
}

#[cfg(test)]
#[test]
fn scheduler_gate_matrix_novovmctl_with_token_passes() {
    assert!(scheduler_context_ok("novovmctl", true));
}

#[cfg(test)]
#[test]
fn scheduler_hard_lock_matrix_contract_is_frozen() {
    assert!(!scheduler_context_ok("manual", false));
    assert!(!scheduler_context_ok("manual", true));
    assert!(!scheduler_context_ok("novovmctl", false));
    assert!(scheduler_context_ok("novovmctl", true));
}

#[cfg(test)]
#[test]
fn mainline_status_freshness_gate_contract_is_frozen() {
    let root = std::path::Path::new(env!("CARGO_MANIFEST_DIR"))
        .join("..")
        .join("..");
    let script_path = root
        .join("scripts")
        .join("_compat")
        .join("Invoke-NovovmctlForward.ps1");
    let preflight_bin_path = root
        .join("crates")
        .join("novovm-node")
        .join("src")
        .join("bin")
        .join("supervm-mainline-preflight.rs");
    let preflight_core_path = root
        .join("crates")
        .join("novovm-node")
        .join("src")
        .join("mainline_preflight.rs");

    let script = std::fs::read_to_string(&script_path).expect("read Invoke-NovovmctlForward.ps1");
    assert!(
        script.contains("supervm-mainline-preflight"),
        "mainline preflight rust gate binary contract missing"
    );
    assert!(
        script.contains("Invoke-MainlinePreflight"),
        "mainline preflight invoke function contract missing"
    );
    assert!(
        script.contains("preflight.failed"),
        "mainline preflight failure contract code changed unexpectedly"
    );

    let preflight_bin =
        std::fs::read_to_string(&preflight_bin_path).expect("read supervm-mainline-preflight.rs");
    assert!(
        preflight_bin.contains("../mainline_preflight.rs"),
        "preflight bin must import shared mainline_preflight module"
    );
    assert!(
        preflight_bin.contains("mainline_preflight::run_preflight"),
        "preflight bin must call shared run_preflight contract"
    );

    let preflight_core =
        std::fs::read_to_string(&preflight_core_path).expect("read mainline_preflight.rs");
    assert!(
        preflight_core.contains("MAINLINE_GATE_LOCKSET_V1"),
        "preflight lockset contract missing"
    );
    assert!(
        preflight_core.contains("REQUIRED_GATE_KEYS_IN_ORDER"),
        "preflight required gate keys contract missing"
    );
    assert!(
        preflight_core.contains("\"schema\": \"supervm-mainline-preflight/v1\""),
        "preflight status block schema contract changed unexpectedly"
    );
    assert!(
        preflight_core.contains("NOVOVM_SUPERVM_MAINLINE_STATUS_MAX_AGE_SECONDS"),
        "preflight freshness env override key changed unexpectedly"
    );
    assert!(
        preflight_core.contains("freshness.expired"),
        "preflight freshness reject code changed unexpectedly"
    );
    assert!(
        preflight_core.contains("gate.key_order_mismatch"),
        "preflight gate key order mismatch code changed unexpectedly"
    );
    assert!(
        preflight_core.contains("gate.keyset_drift"),
        "preflight gate keyset drift code changed unexpectedly"
    );
    assert!(
        preflight_core.contains("gate.lockset_token_order_mismatch"),
        "preflight gate lockset token order mismatch code changed unexpectedly"
    );
    assert!(
        preflight_core.contains("gate.lockset_mismatch"),
        "preflight gate lockset mismatch code changed unexpectedly"
    );
    assert!(
        preflight_core.contains("delivery.status_source_mismatch"),
        "preflight delivery status_source mismatch code changed unexpectedly"
    );
    assert!(
        preflight_core.contains("delivery.gate_entry_mismatch"),
        "preflight delivery gate_entry mismatch code changed unexpectedly"
    );
    assert!(
        preflight_core.contains("delivery.overall_gate_mismatch"),
        "preflight delivery overall gate mismatch code changed unexpectedly"
    );
    assert!(
        preflight_core.contains("delivery.lockset_fieldset_version_mismatch"),
        "preflight delivery lockset fieldset_version mismatch code changed unexpectedly"
    );
}

