fn u64_env_clamped(name: &str, default: u64, min: u64, max: u64) -> u64 {
    std::env::var(name)
        .ok()
        .and_then(|raw| raw.trim().parse::<u64>().ok())
        .map(|v| v.clamp(min, max))
        .unwrap_or(default.clamp(min, max))
}

fn u8_env_clamped(name: &str, default: u8, min: u8, max: u8) -> u8 {
    std::env::var(name)
        .ok()
        .and_then(|raw| raw.trim().parse::<u8>().ok())
        .map(|v| v.clamp(min, max))
        .unwrap_or(default.clamp(min, max))
}

fn now_unix_ms() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|v| v.as_millis() as u64)
        .unwrap_or(0)
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum OverlayRouteDecisionSource {
    Selector,
    OperatorOverride,
}

#[derive(Clone, Debug)]
struct OverlayRouteDecision {
    strategy: String,
    relay_id: Option<String>,
    hop_count: u8,
    source: OverlayRouteDecisionSource,
}

fn overlay_route_uses_relay(strategy: &str) -> bool {
    matches!(strategy, "multi_hop" | "l4_relay" | "l3_relay")
}

fn overlay_route_uses_multi_hop(strategy: &str, hop_count: u8) -> bool {
    overlay_route_uses_relay(strategy) || hop_count > 1
}

fn overlay_route_decision_source_label(source: OverlayRouteDecisionSource) -> &'static str {
    match source {
        OverlayRouteDecisionSource::Selector => "selector",
        OverlayRouteDecisionSource::OperatorOverride => "operator_override",
    }
}

fn overlay_availability_mode_label(mode: AvailabilityMode) -> &'static str {
    match mode {
        AvailabilityMode::Normal => "normal",
        AvailabilityMode::ReadOnly => "read_only",
        AvailabilityMode::QueueOnly => "queue_only",
    }
}

fn overlay_route_mode_for_decision(decision: &OverlayRouteDecision) -> String {
    if overlay_route_uses_multi_hop(&decision.strategy, decision.hop_count) {
        "secure".to_string()
    } else {
        "fast".to_string()
    }
}

fn overlay_route_decision_from_selected_path(path: SelectedPath) -> OverlayRouteDecision {
    match path {
        SelectedPath::DirectL4(_) => OverlayRouteDecision {
            strategy: "direct_l4".to_string(),
            relay_id: None,
            hop_count: 1,
            source: OverlayRouteDecisionSource::Selector,
        },
        SelectedPath::L4Relay(peer) => OverlayRouteDecision {
            strategy: "l4_relay".to_string(),
            relay_id: Some(peer.node_id),
            hop_count: 2,
            source: OverlayRouteDecisionSource::Selector,
        },
        SelectedPath::L3Relay(relay) => OverlayRouteDecision {
            strategy: "l3_relay".to_string(),
            relay_id: Some(relay.node_id),
            hop_count: 2,
            source: OverlayRouteDecisionSource::Selector,
        },
        SelectedPath::ForcedUpstream(_) => OverlayRouteDecision {
            strategy: "forced_upstream".to_string(),
            relay_id: None,
            hop_count: 1,
            source: OverlayRouteDecisionSource::Selector,
        },
        SelectedPath::ReadOnlyQueue => OverlayRouteDecision {
            strategy: "queue_only".to_string(),
            relay_id: None,
            hop_count: 0,
            source: OverlayRouteDecisionSource::Selector,
        },
    }
}

fn operator_forced_overlay_route_decision() -> Option<OverlayRouteDecision> {
    let strategy = string_env_nonempty("NOVOVM_OVERLAY_ROUTE_FORCE_STRATEGY")
        .map(|v| v.to_ascii_lowercase())
        .filter(|v| {
            matches!(
                v.as_str(),
                "direct_l4" | "l4_relay" | "l3_relay" | "forced_upstream" | "queue_only"
            )
        })?;
    let relay_id = string_env_nonempty("NOVOVM_OVERLAY_ROUTE_FORCE_RELAY_ID");
    let default_hops = match strategy.as_str() {
        "direct_l4" | "forced_upstream" => 1,
        "l4_relay" | "l3_relay" => 2,
        "queue_only" => 0,
        _ => 1,
    };
    let hop_count = std::env::var("NOVOVM_OVERLAY_ROUTE_FORCE_HOP_COUNT")
        .ok()
        .and_then(|raw| raw.trim().parse::<u8>().ok())
        .unwrap_or(default_hops);

    Some(OverlayRouteDecision {
        strategy,
        relay_id,
        hop_count,
        source: OverlayRouteDecisionSource::OperatorOverride,
    })
}

fn resolve_overlay_route(selected_path: &SelectedPath) -> OverlayRouteDecision {
    if let Some(override_decision) = operator_forced_overlay_route_decision() {
        return override_decision;
    }
    overlay_route_decision_from_selected_path(selected_path.clone())
}

fn operator_forced_availability_mode() -> Option<AvailabilityMode> {
    let mode =
        string_env_nonempty("NOVOVM_AVAILABILITY_FORCE_MODE").map(|v| v.to_ascii_lowercase())?;
    match mode.as_str() {
        "normal" => Some(AvailabilityMode::Normal),
        "read_only" => Some(AvailabilityMode::ReadOnly),
        "queue_only" => Some(AvailabilityMode::QueueOnly),
        _ => None,
    }
}

fn resolve_availability_decision(
    controller: &AvailabilityController,
    selected_path: &SelectedPath,
    overlay_route_decision: &OverlayRouteDecision,
) -> AvailabilityDecision {
    if let Some(mode) = operator_forced_availability_mode() {
        return match mode {
            AvailabilityMode::Normal => AvailabilityDecision::normal("operator_forced_mode"),
            AvailabilityMode::ReadOnly => AvailabilityDecision::read_only("operator_forced_mode"),
            AvailabilityMode::QueueOnly => AvailabilityDecision::queue_only("operator_forced_mode"),
        };
    }

    if overlay_route_decision.strategy == "queue_only" {
        return AvailabilityDecision::queue_only("operator_override_queue_only");
    }

    controller.decide(selected_path)
}

fn sha256_hex(parts: &[&[u8]]) -> String {
    let mut h = Sha256::new();
    for part in parts {
        h.update(part);
    }
    let digest = h.finalize();
    let mut out = String::with_capacity(digest.len() * 2);
    for b in digest {
        out.push_str(&format!("{b:02x}"));
    }
    out
}

fn queue_request(
    request_id: String,
    source_hint: &str,
    payload: Vec<u8>,
    created_unix_ms: u64,
) -> QueuedRequest {
    let key = sha256_hex(&[source_hint.as_bytes(), &payload]);
    QueuedRequest {
        request_id,
        idempotent_key: key,
        created_unix_ms,
        payload,
    }
}

fn build_queue_store() -> Result<Box<dyn QueueStore>> {
    if let Some(queue_dir) = string_env_nonempty("NOVOVM_AVAILABILITY_QUEUE_DIR") {
        let store = FileQueueStore::new(Path::new(&queue_dir))
            .map_err(|e| anyhow::anyhow!("create file queue store failed: {e}"))?;
        return Ok(Box::new(store));
    }
    Ok(Box::new(InMemoryQueueStore::new()))
}

