fn parse_l3_tuned_i64(
    mode: L3PolicyMode,
    raw: Option<&str>,
    default_value: i64,
    min_value: i64,
    max_value: i64,
) -> (i64, L3PolicySelectionSource, String) {
    let normalized = raw
        .map(str::trim)
        .filter(|v| !v.is_empty())
        .map(|v| v.to_ascii_lowercase());
    if matches!(mode, L3PolicyMode::Baseline) {
        return (
            default_value,
            L3PolicySelectionSource::BaselineLocked,
            normalized.unwrap_or_default(),
        );
    }
    match normalized {
        Some(value) => match value.parse::<i64>() {
            Ok(parsed) if parsed >= min_value && parsed <= max_value => {
                (parsed, L3PolicySelectionSource::EnvExplicit, value)
            }
            Ok(_) => (
                default_value,
                L3PolicySelectionSource::EnvInvalidFallback,
                value,
            ),
            Err(_) => (
                default_value,
                L3PolicySelectionSource::EnvInvalidFallback,
                value,
            ),
        },
        None => (
            default_value,
            L3PolicySelectionSource::DefaultByMode,
            String::new(),
        ),
    }
}

