#[cfg(test)]
fn l3_relay_candidate_chain(
    l3_table: &L3RegionalRoutingTable,
    preferred_relay_id: Option<&str>,
    forced_relay_id: Option<&str>,
    configured_candidates: &[String],
    max_candidates: usize,
    now_unix_ms: u64,
) -> Vec<String> {
    let profile = L3RoutingPolicyProfile::baseline(max_candidates);
    l3_relay_candidate_chain_with_profile(
        l3_table,
        preferred_relay_id,
        forced_relay_id,
        configured_candidates,
        max_candidates,
        now_unix_ms,
        &profile,
    )
}

fn l3_relay_candidate_chain_with_profile(
    l3_table: &L3RegionalRoutingTable,
    preferred_relay_id: Option<&str>,
    forced_relay_id: Option<&str>,
    configured_candidates: &[String],
    max_candidates: usize,
    now_unix_ms: u64,
    profile: &L3RoutingPolicyProfile,
) -> Vec<String> {
    #[derive(Default, Clone, Copy)]
    struct CandidateFlags {
        selected: bool,
        forced: bool,
        pool: bool,
        snapshot: bool,
        configured: bool,
        discovery: bool,
    }

    impl CandidateFlags {
        fn source_bonus(self, profile: &L3RoutingPolicyProfile) -> i64 {
            let mut bonus = 0i64;
            if self.configured && profile.governance.allows_configured() {
                bonus += L3_RELAY_SOURCE_BONUS_CONFIGURED;
            }
            if self.snapshot && profile.governance.allows_snapshot() {
                bonus += L3_RELAY_SOURCE_BONUS_SNAPSHOT;
            }
            if self.pool {
                bonus += L3_RELAY_SOURCE_BONUS_POOL;
            }
            if self.discovery && profile.governance.allows_discovery() {
                bonus += L3_RELAY_SOURCE_BONUS_DISCOVERY;
            }
            bonus
        }
    }

    #[derive(Clone)]
    struct RankedCandidate {
        relay_id: String,
        forced: bool,
        selected: bool,
        health_rank: u8,
        composite: i64,
    }

    fn trim_nonempty(v: &str) -> Option<&str> {
        let t = v.trim();
        if t.is_empty() {
            None
        } else {
            Some(t)
        }
    }

    fn health_rank_for_sort(health: RelayHealth) -> u8 {
        match health {
            RelayHealth::Healthy => 0,
            RelayHealth::Degraded => 1,
            RelayHealth::Unavailable => 2,
        }
    }

    fn is_discovery_source(source: RoutingSource) -> bool {
        matches!(
            source,
            RoutingSource::PeerHinted
                | RoutingSource::RegionalAnnounced
                | RoutingSource::LocalObserved
        )
    }

    let mut out = Vec::new();
    let max_candidates = max_candidates.max(1).min(profile.candidate_limit.max(1));
    let soft_scan_limit = max_candidates.saturating_mul(4).max(4);
    let mut flags_map: HashMap<String, CandidateFlags> = HashMap::new();

    if let Some(preferred) = preferred_relay_id.and_then(trim_nonempty) {
        flags_map.entry(preferred.to_string()).or_default().selected = true;
    }
    if let Some(forced) = forced_relay_id.and_then(trim_nonempty) {
        flags_map.entry(forced.to_string()).or_default().forced = true;
    }
    for relay in l3_table.relay_pool(now_unix_ms, soft_scan_limit) {
        let flags = flags_map.entry(relay.node_id).or_default();
        flags.pool = true;
        if is_discovery_source(relay.source) {
            flags.discovery = true;
        }
    }
    if profile.governance.allows_snapshot() {
        for view in l3_table.relay_score_snapshot().iter().take(soft_scan_limit) {
            flags_map.entry(view.relay_id.clone()).or_default().snapshot = true;
        }
    }
    if profile.governance.allows_configured() {
        for candidate in configured_candidates {
            if let Some(id) = trim_nonempty(candidate) {
                flags_map.entry(id.to_string()).or_default().configured = true;
            }
        }
    }

    let mut available_ranked: Vec<RankedCandidate> = flags_map
        .iter()
        .filter_map(|(relay_id, flags)| {
            if !l3_table.relay_is_available(relay_id, now_unix_ms) {
                return None;
            }
            if flags.discovery
                && !profile.governance.allows_discovery()
                && !flags.forced
                && !flags.selected
                && !flags.configured
            {
                return None;
            }
            let view = l3_table.relay_score_view(relay_id);
            let health_rank = view
                .as_ref()
                .map(|v| health_rank_for_sort(v.health))
                .unwrap_or(3);
            let score = view.map(|v| v.score).unwrap_or(-100);
            let runtime_feedback = l3_table.relay_runtime_feedback_score(relay_id, now_unix_ms);
            let composite = (score as i64) * L3_RELAY_SCORE_SCALE
                + flags.source_bonus(profile)
                + runtime_feedback * profile.runtime_feedback_scale;
            Some(RankedCandidate {
                relay_id: relay_id.clone(),
                forced: flags.forced,
                selected: flags.selected,
                health_rank,
                composite,
            })
        })
        .collect();

    available_ranked.sort_by(|left, right| {
        right
            .forced
            .cmp(&left.forced)
            .then_with(|| left.health_rank.cmp(&right.health_rank))
            .then_with(|| right.composite.cmp(&left.composite))
            .then_with(|| left.relay_id.cmp(&right.relay_id))
    });

    let non_forced_start = available_ranked
        .iter()
        .position(|candidate| !candidate.forced)
        .unwrap_or(available_ranked.len());
    if non_forced_start < available_ranked.len() {
        if let Some(selected_idx) =
            available_ranked
                .iter()
                .enumerate()
                .find_map(|(idx, candidate)| {
                    if idx >= non_forced_start && candidate.selected {
                        Some(idx)
                    } else {
                        None
                    }
                })
        {
            let top = &available_ranked[non_forced_start];
            let selected = &available_ranked[selected_idx];
            if selected.health_rank == top.health_rank
                && selected.composite + profile.sticky_margin >= top.composite
                && selected_idx != non_forced_start
            {
                let selected_candidate = available_ranked.remove(selected_idx);
                available_ranked.insert(non_forced_start, selected_candidate);
            }
        }
    }

    for candidate in available_ranked.into_iter().take(max_candidates) {
        out.push(candidate.relay_id);
    }

    if out.is_empty() {
        if let Some(forced) = forced_relay_id.and_then(trim_nonempty) {
            out.push(forced.to_string());
        } else if let Some(preferred) = preferred_relay_id.and_then(trim_nonempty) {
            out.push(preferred.to_string());
        } else if profile.governance.allows_configured() {
            if let Some(first_cfg) = configured_candidates.iter().find_map(|v| trim_nonempty(v)) {
                out.push(first_cfg.to_string());
            }
        }
    }

    out.truncate(max_candidates);
    out
}

fn availability_relay_path_log_line(
    relay_id: &str,
    relay_ok: bool,
    fallback: &str,
    final_ok: bool,
) -> String {
    format!(
        "availability_relay_path: relay_id={} relay_ok={} fallback={} final_ok={}",
        relay_id, relay_ok, fallback, final_ok
    )
}

fn availability_relay_score_log_line(
    selected: &str,
    health: RelayHealth,
    score: i32,
    delta: i32,
    final_score: i32,
) -> String {
    format!(
        "availability_relay_score: selected={} health={:?} score={} delta={} final_score={}",
        selected, health, score, delta, final_score
    )
}

fn relay_attempt_reason(
    idx: usize,
    relay_id: &str,
    selected_relay_id: Option<&str>,
) -> &'static str {
    if idx > 0 {
        return "relay_once_failover";
    }
    if selected_relay_id
        .map(str::trim)
        .filter(|v| !v.is_empty())
        .map(|selected| selected == relay_id)
        .unwrap_or(false)
    {
        "selected_primary"
    } else {
        "candidate_primary"
    }
}

fn availability_l3_route_log_line(
    candidates: &[String],
    selected: &str,
    reason: &str,
    fallback: &str,
    final_ok: bool,
) -> String {
    let (candidate_count, primary, selected_index) = l3_route_selection_view(candidates, selected);
    format!(
        "availability_l3_route: candidates={} candidate_count={} primary={} selected={} selected_index={} reason={} fallback={} final_ok={}",
        candidates.join("|"),
        candidate_count,
        primary,
        selected,
        selected_index,
        reason,
        fallback,
        final_ok
    )
}

fn l3_route_selection_view(candidates: &[String], selected: &str) -> (usize, String, i64) {
    let candidate_count = candidates.len();
    let primary = candidates
        .first()
        .map(String::as_str)
        .unwrap_or("-")
        .to_string();
    let selected_index = candidates
        .iter()
        .position(|v| v == selected)
        .map(|idx| idx as i64)
        .unwrap_or(-1);
    (candidate_count, primary, selected_index)
}

fn l2_l1_cross_path_health_view(
    state_seal_hash: u64,
    replay_seal_hash: u64,
    watch_seal_hash: u64,
    batch_seal_hash: u64,
) -> (bool, usize, String) {
    let mut mismatch_paths: Vec<&str> = Vec::new();
    if replay_seal_hash != state_seal_hash {
        mismatch_paths.push("replay");
    }
    if watch_seal_hash != state_seal_hash {
        mismatch_paths.push("watch");
    }
    if batch_seal_hash != state_seal_hash {
        mismatch_paths.push("batch");
    }
    let consistent = mismatch_paths.is_empty();
    let mismatch_count = mismatch_paths.len();
    let mismatch_paths = if consistent {
        "-".to_string()
    } else {
        mismatch_paths.join(",")
    };
    (consistent, mismatch_count, mismatch_paths)
}

