fn build_l4_readonly_export(
    l4_table: &L4LocalRoutingTable,
    direct_candidate_limit: usize,
    freshness_window_ms: u64,
) -> L4ReadonlyExport {
    let snapshot = l4_table.snapshot();
    let mut local_observed_reachable: usize = 0;
    let mut local_observed_unknown: usize = 0;
    let mut operator_forced_unknown: usize = 0;

    for peer in &snapshot.peers {
        match (peer.source, peer.reachability) {
            (RoutingSource::LocalObserved, Reachability::Reachable) => {
                local_observed_reachable = local_observed_reachable.saturating_add(1);
            }
            (RoutingSource::LocalObserved, Reachability::Unknown) => {
                local_observed_unknown = local_observed_unknown.saturating_add(1);
            }
            (RoutingSource::OperatorForced, Reachability::Unknown) => {
                operator_forced_unknown = operator_forced_unknown.saturating_add(1);
            }
            _ => {}
        }
    }

    let direct_candidates = l4_table.best_direct_candidates(direct_candidate_limit);
    let direct_candidate_chain = direct_candidates
        .iter()
        .map(|peer| peer.node_id.clone())
        .collect::<Vec<_>>()
        .join("|");

    L4ReadonlyExport {
        baseline_phase: L4_READONLY_BASELINE_PHASE.to_string(),
        baseline_lock_version: L4_READONLY_BASELINE_LOCK_VERSION,
        readonly_export_version: L4_READONLY_EXPORT_VERSION,
        fieldset_version: L4_READONLY_FIELDSET_VERSION,
        fieldset_fingerprint: L4_READONLY_FIELDSET_FINGERPRINT.to_string(),
        field_ordering: L4_READONLY_FIELD_ORDERING.to_string(),
        regression_lockset: L4_READONLY_REGRESSION_LOCKSET.to_string(),
        baseline_fingerprint: L4_READONLY_BASELINE_FINGERPRINT.to_string(),
        owner_node_id: snapshot.owner_node_id,
        table_version: snapshot.version,
        peer_total: snapshot.peers.len(),
        local_observed_reachable,
        local_observed_unknown,
        operator_forced_unknown,
        direct_candidate_chain,
        direct_candidate_count: direct_candidates.len(),
        freshness_window_ms,
    }
}

fn apply_relay_score_feedback(
    l3_table: &L3RegionalRoutingTable,
    relay_id: &str,
    ok: bool,
    relay_fail_cooldown_ms: u64,
    verbose: bool,
    mut emit_log: impl FnMut(String),
) {
    let Some(before) = l3_table.relay_score_view(relay_id) else {
        return;
    };
    let delta = if ok { 1 } else { -1 };
    if ok {
        let _ = l3_table.mark_relay_success(relay_id);
    } else {
        let _ = l3_table.mark_relay_failure(relay_id, now_unix_ms(), relay_fail_cooldown_ms);
    }
    let final_score = l3_table
        .relay_score_view(relay_id)
        .map(|v| v.score)
        .unwrap_or(before.score);
    if verbose {
        emit_log(availability_relay_score_log_line(
            relay_id,
            before.health,
            before.score,
            delta,
            final_score,
        ));
    }
}

fn submit_ops_wire_report_with_route_and_log_with_fallback(
    overlay_route_strategy: &str,
    overlay_route_selected_relay_id: Option<&str>,
    relay_candidates: &[String],
    request_id: String,
    payload: &[u8],
    fallback_mode: RelayFailFallbackMode,
    verbose: bool,
    mut emit_log: impl FnMut(String),
    mut on_relay_outcome: impl FnMut(&str, bool),
    mut submit: impl FnMut(&[u8]) -> AoemSubmitReport,
) -> AoemSubmitReport {
    if overlay_route_strategy != "l3_relay" {
        return submit(payload);
    }

    let mut relay_attempt_order: Vec<String> = Vec::new();
    if let Some(primary_relay_id) = overlay_route_selected_relay_id
        .map(str::trim)
        .filter(|v| !v.is_empty())
    {
        relay_attempt_order.push(primary_relay_id.to_string());
    }
    for candidate in relay_candidates {
        if relay_attempt_order.len() >= 2 {
            break;
        }
        let candidate = candidate.trim();
        if candidate.is_empty() {
            continue;
        }
        if relay_attempt_order.iter().any(|id| id == candidate) {
            continue;
        }
        relay_attempt_order.push(candidate.to_string());
    }
    if relay_attempt_order.is_empty() {
        relay_attempt_order.push("l3-relay-unspecified".to_string());
    }

    let mut last_report: Option<AoemSubmitReport> = None;
    let mut last_relay_id = relay_attempt_order
        .first()
        .cloned()
        .unwrap_or_else(|| "l3-relay-unspecified".to_string());

    for (idx, relay_id) in relay_attempt_order.iter().enumerate() {
        let relay_server = RelayServer::new(relay_id.clone());
        let relay_client =
            RelayClient::new(relay_id.clone(), "aoem_exec".to_string(), &relay_server);
        let attempt_request_id = if idx == 0 {
            request_id.clone()
        } else {
            format!("{request_id}:relay_once:{idx}")
        };
        let relayed =
            relay_client.forward_with(attempt_request_id, payload.to_vec(), |_target, wire| {
                let report = submit(wire);
                (report.ok, report)
            });
        let relay_report = relayed.response;
        let relay_ok = relay_report.ok;
        let relay_id = relay_client.relay_id().to_string();
        on_relay_outcome(&relay_id, relay_ok);
        last_relay_id = relay_id.clone();
        if relay_ok {
            let fallback = if idx == 0 { "none" } else { "relay_once" };
            let reason = relay_attempt_reason(idx, &relay_id, overlay_route_selected_relay_id);
            if verbose {
                emit_log(availability_relay_path_log_line(
                    &relay_id, true, fallback, true,
                ));
                emit_log(availability_l3_route_log_line(
                    &relay_attempt_order,
                    &relay_id,
                    reason,
                    fallback,
                    true,
                ));
            }
            return relay_report;
        }
        last_report = Some(relay_report);
    }

    match fallback_mode {
        RelayFailFallbackMode::DirectOnce => {
            let fallback_report = submit(payload);
            let fallback_label = if relay_attempt_order.len() > 1 {
                "relay_once+direct_once"
            } else {
                "direct_once"
            };
            if verbose {
                emit_log(availability_relay_path_log_line(
                    &last_relay_id,
                    false,
                    fallback_label,
                    fallback_report.ok,
                ));
                emit_log(availability_l3_route_log_line(
                    &relay_attempt_order,
                    &last_relay_id,
                    "direct_once_after_relay_failure",
                    fallback_label,
                    fallback_report.ok,
                ));
            }
            fallback_report
        }
        RelayFailFallbackMode::Off => {
            if verbose {
                emit_log(availability_relay_path_log_line(
                    &last_relay_id,
                    false,
                    if relay_attempt_order.len() > 1 {
                        "relay_once"
                    } else {
                        "off"
                    },
                    false,
                ));
                emit_log(availability_l3_route_log_line(
                    &relay_attempt_order,
                    &last_relay_id,
                    if relay_attempt_order.len() > 1 {
                        "relay_once_exhausted"
                    } else {
                        "relay_primary_failed"
                    },
                    if relay_attempt_order.len() > 1 {
                        "relay_once"
                    } else {
                        "off"
                    },
                    false,
                ));
            }
            last_report.unwrap_or_else(|| {
                let mut fallback = submit(payload);
                fallback.ok = false;
                fallback
            })
        }
    }
}

fn submit_ops_wire_report_with_route_and_log(
    overlay_route_strategy: &str,
    overlay_route_selected_relay_id: Option<&str>,
    relay_candidates: &[String],
    request_id: String,
    payload: &[u8],
    fallback_mode: RelayFailFallbackMode,
    verbose: bool,
    mut emit_log: impl FnMut(String),
    mut on_relay_outcome: impl FnMut(&str, bool),
    submit: impl FnMut(&[u8]) -> AoemSubmitReport,
) -> AoemSubmitReport {
    submit_ops_wire_report_with_route_and_log_with_fallback(
        overlay_route_strategy,
        overlay_route_selected_relay_id,
        relay_candidates,
        request_id,
        payload,
        fallback_mode,
        verbose,
        |line| emit_log(line),
        |relay_id, ok| on_relay_outcome(relay_id, ok),
        submit,
    )
}

fn submit_ops_wire_report_with_route(
    overlay_route_strategy: &str,
    overlay_route_selected_relay_id: Option<&str>,
    relay_candidates: &[String],
    request_id: String,
    payload: &[u8],
    fallback_mode: RelayFailFallbackMode,
    verbose: bool,
    mut on_relay_outcome: impl FnMut(&str, bool),
    submit: impl FnMut(&[u8]) -> AoemSubmitReport,
) -> AoemSubmitReport {
    submit_ops_wire_report_with_route_and_log(
        overlay_route_strategy,
        overlay_route_selected_relay_id,
        relay_candidates,
        request_id,
        payload,
        fallback_mode,
        verbose,
        |line| println!("{line}"),
        |relay_id, ok| on_relay_outcome(relay_id, ok),
        submit,
    )
}

