    fn fake_report(ok: bool, name: &str) -> AoemSubmitReport {
        AoemSubmitReport {
            return_code: if ok { 0 } else { 1 },
            return_code_name: name.to_string(),
            ok,
            output: None,
            error: None,
        }
    }

    #[test]
    fn l3_relay_executes_and_emits_success_log() {
        let mut logs = Vec::new();
        let report = submit_ops_wire_report_with_route_and_log_with_fallback(
            "l3_relay",
            Some("relay-eu-01"),
            &[],
            "req-1".to_string(),
            b"wire_payload",
            RelayFailFallbackMode::Off,
            true,
            |line| logs.push(line),
            |_relay_id, _ok| {},
            |wire| {
                assert_eq!(wire, b"wire_payload");
                fake_report(true, "ok")
            },
        );

        assert!(report.ok);
        assert_eq!(logs.len(), 2);
        assert_eq!(
            logs[0],
            availability_relay_path_log_line("relay-eu-01", true, "none", true)
        );
        assert!(logs[1].contains("availability_l3_route:"));
        assert!(logs[1].contains("reason=selected_primary"));
    }

    #[test]
    fn l3_relay_executes_and_emits_failure_log() {
        let mut logs = Vec::new();
        let report = submit_ops_wire_report_with_route_and_log_with_fallback(
            "l3_relay",
            Some("relay-eu-02"),
            &[],
            "req-2".to_string(),
            b"wire_payload_2",
            RelayFailFallbackMode::Off,
            true,
            |line| logs.push(line),
            |_relay_id, _ok| {},
            |_wire| fake_report(false, "engine_exec_failed"),
        );

        assert!(!report.ok);
        assert_eq!(logs.len(), 2);
        assert_eq!(
            logs[0],
            availability_relay_path_log_line("relay-eu-02", false, "off", false)
        );
        assert!(logs[1].contains("availability_l3_route:"));
        assert!(logs[1].contains("reason=relay_primary_failed"));
    }

    #[test]
    fn l3_relay_fallback_direct_once_can_recover() {
        let mut logs = Vec::new();
        let mut call_count = 0usize;
        let report = submit_ops_wire_report_with_route_and_log_with_fallback(
            "l3_relay",
            Some("relay-eu-03"),
            &[],
            "req-3".to_string(),
            b"wire_payload_3",
            RelayFailFallbackMode::DirectOnce,
            true,
            |line| logs.push(line),
            |_relay_id, _ok| {},
            |_wire| {
                call_count += 1;
                if call_count == 1 {
                    fake_report(false, "relay_failed")
                } else {
                    fake_report(true, "direct_fallback_ok")
                }
            },
        );

        assert!(report.ok);
        assert_eq!(report.return_code_name, "direct_fallback_ok");
        assert_eq!(call_count, 2);
        assert_eq!(logs.len(), 2);
        assert_eq!(
            logs[0],
            availability_relay_path_log_line("relay-eu-03", false, "direct_once", true)
        );
        assert!(logs[1].contains("availability_l3_route:"));
        assert!(logs[1].contains("reason=direct_once_after_relay_failure"));
    }

