    #[test]
    fn relay_candidate_chain_runtime_feedback_promotes_successful_relay() {
        let l3 = L3RegionalRoutingTable::new("ap-east");
        l3.upsert_l3_relay(RelayRef {
            node_id: "relay-a".into(),
            region: "ap-east".into(),
            addr: "127.0.0.1:9901".into(),
            capacity_class: RelayCapacityClass::Medium,
            health: RelayHealth::Healthy,
            score: 5,
            source: RoutingSource::RegionalAnnounced,
        });
        l3.upsert_l3_relay(RelayRef {
            node_id: "relay-b".into(),
            region: "ap-east".into(),
            addr: "127.0.0.1:9902".into(),
            capacity_class: RelayCapacityClass::Medium,
            health: RelayHealth::Healthy,
            score: 5,
            source: RoutingSource::RegionalAnnounced,
        });

        let now = 1_000_000u64;
        assert!(l3.mark_relay_success("relay-b"));
        assert!(l3.bump_relay_score("relay-b", -1));
        assert!(l3.mark_relay_failure("relay-a", now, 0));
        assert!(l3.bump_relay_score("relay-a", 1));

        let chain = l3_relay_candidate_chain(&l3, None, None, &[], 2, now);
        assert_eq!(chain, vec!["relay-b".to_string(), "relay-a".to_string()]);
    }

    #[test]
    fn discovery_membership_respects_pool_only_governance() {
        let l3 = L3RegionalRoutingTable::new("ap-east");
        l3.upsert_l3_relay_discovered(RelayRef {
            node_id: "relay-discovery".into(),
            region: "ap-east".into(),
            addr: "127.0.0.1:9921".into(),
            capacity_class: RelayCapacityClass::Large,
            health: RelayHealth::Healthy,
            score: 10,
            source: RoutingSource::PeerHinted,
        });
        l3.upsert_l3_relay(RelayRef {
            node_id: "relay-operator".into(),
            region: "ap-east".into(),
            addr: "127.0.0.1:9922".into(),
            capacity_class: RelayCapacityClass::Medium,
            health: RelayHealth::Healthy,
            score: 1,
            source: RoutingSource::OperatorForced,
        });

        let profile_pool_only = L3RoutingPolicyProfile {
            mode: L3PolicyMode::FastFailover,
            governance: L3CandidateSourceGovernance::PoolOnly,
            sticky_margin: L3_RELAY_SELECTED_STICKY_MARGIN,
            runtime_feedback_scale: L3_RELAY_RUNTIME_FEEDBACK_SCALE,
            candidate_limit: 2,
        };

        let chain = l3_relay_candidate_chain_with_profile(
            &l3,
            None,
            None,
            &[],
            2,
            1_000_000,
            &profile_pool_only,
        );
        assert_eq!(chain, vec!["relay-operator".to_string()]);
    }

    #[test]
    fn l3_candidate_source_governance_equivalence_for_discovery_membership() {
        let l3 = L3RegionalRoutingTable::new("ap-east");
        l3.upsert_l3_relay_discovered(RelayRef {
            node_id: "relay-a-discovery".into(),
            region: "ap-east".into(),
            addr: "127.0.0.1:9931".into(),
            capacity_class: RelayCapacityClass::Large,
            health: RelayHealth::Healthy,
            score: 9,
            source: RoutingSource::RegionalAnnounced,
        });
        l3.upsert_l3_relay(RelayRef {
            node_id: "relay-z-operator".into(),
            region: "ap-east".into(),
            addr: "127.0.0.1:9932".into(),
            capacity_class: RelayCapacityClass::Medium,
            health: RelayHealth::Healthy,
            score: 1,
            source: RoutingSource::OperatorForced,
        });

        let baseline_profile = L3RoutingPolicyProfile {
            mode: L3PolicyMode::Baseline,
            governance: L3CandidateSourceGovernance::Baseline,
            sticky_margin: L3_RELAY_SELECTED_STICKY_MARGIN,
            runtime_feedback_scale: L3_RELAY_RUNTIME_FEEDBACK_SCALE,
            candidate_limit: 2,
        };
        let baseline_chain = l3_relay_candidate_chain_with_profile(
            &l3,
            None,
            None,
            &[],
            2,
            1_000_000,
            &baseline_profile,
        );
        assert_eq!(baseline_chain[0], "relay-a-discovery");

        let pool_only_profile = L3RoutingPolicyProfile {
            mode: L3PolicyMode::FastFailover,
            governance: L3CandidateSourceGovernance::PoolOnly,
            sticky_margin: L3_RELAY_SELECTED_STICKY_MARGIN,
            runtime_feedback_scale: L3_RELAY_RUNTIME_FEEDBACK_SCALE,
            candidate_limit: 2,
        };
        let pool_only_chain = l3_relay_candidate_chain_with_profile(
            &l3,
            None,
            None,
            &[],
            2,
            1_000_000,
            &pool_only_profile,
        );
        assert_eq!(pool_only_chain, vec!["relay-z-operator".to_string()]);
    }

