    #[test]
    fn discovery_membership_freshness_drops_stale_entries() {
        let now = 1_700_000_100_000u64;
        let max_age_ms = 60_000u64;
        let (entries, stale) = filter_l3_discovery_membership_fresh(
            vec![
                RelayMembership {
                    relay_id: "relay-fresh".to_string(),
                    region: Some("ap-east".to_string()),
                    addr: Some("10.0.0.1:9001".to_string()),
                    health: Some("healthy".to_string()),
                    capacity_class: Some("medium".to_string()),
                    score_hint: Some(1),
                    seen_unix_ms: Some(now.saturating_sub(max_age_ms)),
                },
                RelayMembership {
                    relay_id: "relay-stale".to_string(),
                    region: Some("ap-east".to_string()),
                    addr: Some("10.0.0.2:9001".to_string()),
                    health: Some("healthy".to_string()),
                    capacity_class: Some("medium".to_string()),
                    score_hint: Some(2),
                    seen_unix_ms: Some(now.saturating_sub(max_age_ms + 1)),
                },
            ],
            now,
            max_age_ms,
        );
        assert_eq!(stale, 1);
        assert_eq!(entries.len(), 1);
        assert_eq!(entries[0].relay_id, "relay-fresh");
    }

