    fn runtime_membership_test_guard() -> std::sync::MutexGuard<'static, ()> {
        static LOCK: std::sync::OnceLock<std::sync::Mutex<()>> = std::sync::OnceLock::new();
        let guard = LOCK
            .get_or_init(|| std::sync::Mutex::new(()))
            .lock()
            .unwrap_or_else(|e| e.into_inner());
        if let Ok(mut state) = super::runtime_membership_gossip_publish_state().lock() {
            state.clear();
        }
        if let Ok(mut state) = super::local_observed_membership_state().lock() {
            state.clear();
        }
        guard
    }

    #[test]
    fn runtime_membership_dedup_prefers_newer_seen_over_higher_score() {
        let _guard = runtime_membership_test_guard();
        let _ = super::drain_runtime_relay_membership();
        let table = L3RegionalRoutingTable::new("ap-east");
        let now = super::now_unix_ms();
        let inserted = super::ingest_runtime_relay_membership(vec![
            RelayMembership {
                relay_id: "relay-dedup-seen".to_string(),
                region: Some("ap-east".to_string()),
                addr: Some("10.1.0.10:9001".to_string()),
                health: Some("healthy".to_string()),
                capacity_class: Some("large".to_string()),
                score_hint: Some(99),
                seen_unix_ms: Some(now.saturating_sub(5_000)),
            },
            RelayMembership {
                relay_id: "relay-dedup-seen".to_string(),
                region: Some("ap-east".to_string()),
                addr: Some("10.1.0.11:9001".to_string()),
                health: Some("degraded".to_string()),
                capacity_class: Some("small".to_string()),
                score_hint: Some(1),
                seen_unix_ms: Some(now),
            },
        ]);
        assert_eq!(inserted, 1);
        let _ = super::refresh_l3_discovery_membership(&table, "ap-east", false);
        let view = table
            .relay_score_view("relay-dedup-seen")
            .expect("relay should be present");
        assert_eq!(view.score, 1);
        assert_eq!(view.health, RelayHealth::Degraded);
        let _ = super::drain_runtime_relay_membership();
    }

    #[test]
    fn runtime_membership_dedup_prefers_health_capacity_when_seen_and_score_tie() {
        let _guard = runtime_membership_test_guard();
        let _ = super::drain_runtime_relay_membership();
        let table = L3RegionalRoutingTable::new("ap-east");
        let now = super::now_unix_ms();
        let inserted = super::ingest_runtime_relay_membership(vec![
            RelayMembership {
                relay_id: "relay-dedup-tie".to_string(),
                region: Some("ap-east".to_string()),
                addr: Some("10.2.0.10:9001".to_string()),
                health: Some("degraded".to_string()),
                capacity_class: Some("small".to_string()),
                score_hint: Some(7),
                seen_unix_ms: Some(now),
            },
            RelayMembership {
                relay_id: "relay-dedup-tie".to_string(),
                region: Some("ap-east".to_string()),
                addr: Some("10.2.0.11:9001".to_string()),
                health: Some("healthy".to_string()),
                capacity_class: Some("large".to_string()),
                score_hint: Some(7),
                seen_unix_ms: Some(now),
            },
        ]);
        assert_eq!(inserted, 1);
        let _ = super::refresh_l3_discovery_membership(&table, "ap-east", false);
        let view = table
            .relay_score_view("relay-dedup-tie")
            .expect("relay should be present");
        assert_eq!(view.score, 7);
        assert_eq!(view.health, RelayHealth::Healthy);
        let pool = table.relay_pool(super::now_unix_ms(), 8);
        let picked = pool
            .iter()
            .find(|r| r.node_id == "relay-dedup-tie")
            .expect("relay should exist in pool");
        assert_eq!(picked.capacity_class, RelayCapacityClass::Large);
        assert_eq!(picked.addr, "10.2.0.11:9001");
        let _ = super::drain_runtime_relay_membership();
    }

    #[test]
    fn runtime_membership_dedup_prefers_source_over_score_when_seen_ties() {
        let seen = 1_700_000_220_000u64;
        let regional_high_score = RelayMembership {
            relay_id: "relay-dedup-source".to_string(),
            region: Some("ap-east".to_string()),
            addr: Some("10.2.1.10:9001".to_string()),
            health: Some("healthy".to_string()),
            capacity_class: Some("large".to_string()),
            score_hint: Some(99),
            seen_unix_ms: Some(seen),
        };
        let peer_hinted_lower_score = RelayMembership {
            relay_id: "relay-dedup-source".to_string(),
            region: Some("ap-east".to_string()),
            addr: Some("10.2.1.11:9001".to_string()),
            health: Some("healthy".to_string()),
            capacity_class: Some("large".to_string()),
            score_hint: Some(1),
            seen_unix_ms: Some(seen),
        };
        let regional_key = super::relay_membership_priority_key(
            &regional_high_score,
            RoutingSource::RegionalAnnounced,
        );
        let peer_hinted_key = super::relay_membership_priority_key(
            &peer_hinted_lower_score,
            RoutingSource::PeerHinted,
        );
        assert!(
            peer_hinted_key > regional_key,
            "source priority must dominate score when seen timestamps tie"
        );
    }

