    #[test]
    fn runtime_membership_unavailable_update_prunes_existing_discovered_relay() {
        let _guard = runtime_membership_test_guard();
        let _ = super::drain_runtime_relay_membership();
        let table = L3RegionalRoutingTable::new("ap-east");

        let first = super::relay_membership_entries_from_relays(
            vec![RelayRef {
                node_id: "relay-flap".to_string(),
                region: "ap-east".to_string(),
                addr: "10.0.0.31:9001".to_string(),
                capacity_class: RelayCapacityClass::Medium,
                health: RelayHealth::Healthy,
                score: 6,
                source: RoutingSource::PeerHinted,
            }],
            super::now_unix_ms(),
        );
        assert_eq!(super::ingest_runtime_relay_membership(first), 1);
        assert_eq!(
            super::refresh_l3_discovery_membership(&table, "ap-east", false),
            1
        );
        let first_chain = l3_relay_candidate_chain_with_profile(
            &table,
            None,
            None,
            &[],
            2,
            super::now_unix_ms(),
            &L3RoutingPolicyProfile {
                mode: L3PolicyMode::Baseline,
                governance: L3CandidateSourceGovernance::Baseline,
                sticky_margin: L3_RELAY_SELECTED_STICKY_MARGIN,
                runtime_feedback_scale: L3_RELAY_RUNTIME_FEEDBACK_SCALE,
                candidate_limit: 2,
            },
        );
        assert!(first_chain.iter().any(|id| id == "relay-flap"));

        let second = super::relay_membership_entries_from_relays(
            vec![RelayRef {
                node_id: "relay-flap".to_string(),
                region: "ap-east".to_string(),
                addr: "10.0.0.31:9001".to_string(),
                capacity_class: RelayCapacityClass::Medium,
                health: RelayHealth::Unavailable,
                score: 8,
                source: RoutingSource::PeerHinted,
            }],
            super::now_unix_ms(),
        );
        assert_eq!(super::ingest_runtime_relay_membership(second), 1);
        assert_eq!(
            super::refresh_l3_discovery_membership(&table, "ap-east", false),
            0
        );
        let second_chain = l3_relay_candidate_chain_with_profile(
            &table,
            None,
            None,
            &[],
            2,
            super::now_unix_ms(),
            &L3RoutingPolicyProfile {
                mode: L3PolicyMode::Baseline,
                governance: L3CandidateSourceGovernance::Baseline,
                sticky_margin: L3_RELAY_SELECTED_STICKY_MARGIN,
                runtime_feedback_scale: L3_RELAY_RUNTIME_FEEDBACK_SCALE,
                candidate_limit: 2,
            },
        );
        assert!(!second_chain.iter().any(|id| id == "relay-flap"));
        let _ = super::drain_runtime_relay_membership();
    }

    #[test]
