    #[test]
    fn discovery_membership_gossip_json_supports_single_and_vec_message() {
        let members = vec![RelayMembership {
            relay_id: "relay-gossip-a".to_string(),
            region: Some("ap-east".to_string()),
            addr: Some("10.10.0.1:9001".to_string()),
            health: Some("healthy".to_string()),
            capacity_class: Some("medium".to_string()),
            score_hint: Some(2),
            seen_unix_ms: Some(1_700_000_000_123),
        }];
        let payload = serde_json::to_vec(&members).expect("encode relay membership payload");
        let message = GossipMessage {
            from: 1,
            to: 2,
            msg_type: MessageType::RelayMembership,
            payload,
            timestamp: 1,
            seq: 1,
        };

        let single_raw = serde_json::to_string(&message).expect("encode single gossip message");
        let single_decoded = parse_l3_discovery_membership_gossip_json(&single_raw)
            .expect("decode single gossip membership");
        assert_eq!(single_decoded, members);

        let vec_raw = serde_json::to_string(&vec![message]).expect("encode vec gossip message");
        let vec_decoded = parse_l3_discovery_membership_gossip_json(&vec_raw)
            .expect("decode vec gossip membership");
        assert_eq!(vec_decoded, members);
    }

