    #[test]
    fn l2_state_snapshot_preserves_counter_mapping() {
        let snapshot = build_l2_state_snapshot(
            9,  // queue_total
            11, // replay_applied_total
            12, // replay_retry_later_total
            13, // replay_rejected_total
            21, // reconcile_pending_total
            22, // reconcile_applied_total
            23, // reconcile_retry_later_total
            24, // reconcile_rejected_total
            25, // reconcile_unknown_total
        );

        assert_eq!(snapshot.queue_total, 9);
        assert_eq!(snapshot.replay_applied_total, 11);
        assert_eq!(snapshot.replay_retry_later_total, 12);
        assert_eq!(snapshot.replay_rejected_total, 13);
        assert_eq!(snapshot.reconcile_pending_total, 21);
        assert_eq!(snapshot.reconcile_applied_total, 22);
        assert_eq!(snapshot.reconcile_retry_later_total, 23);
        assert_eq!(snapshot.reconcile_rejected_total, 24);
        assert_eq!(snapshot.reconcile_unknown_total, 25);
    }

