    #[test]
    fn l2_l1_runtime_tripwire_and_versions_are_consistent_across_batch_replay_watch_samples() {
        let samples = [
            (
                "batch",
                L2RuntimeCounters {
                    queue_total: 3,
                    replay_applied_total: 1,
                    replay_retry_later_total: 0,
                    replay_rejected_total: 0,
                    reconcile_pending_total: 2,
                    reconcile_applied_total: 1,
                    reconcile_retry_later_total: 1,
                    reconcile_rejected_total: 0,
                    reconcile_unknown_total: 0,
                },
            ),
            (
                "replay",
                L2RuntimeCounters {
                    queue_total: 8,
                    replay_applied_total: 5,
                    replay_retry_later_total: 2,
                    replay_rejected_total: 1,
                    reconcile_pending_total: 3,
                    reconcile_applied_total: 5,
                    reconcile_retry_later_total: 2,
                    reconcile_rejected_total: 1,
                    reconcile_unknown_total: 0,
                },
            ),
            (
                "watch",
                L2RuntimeCounters {
                    queue_total: 11,
                    replay_applied_total: 7,
                    replay_retry_later_total: 1,
                    replay_rejected_total: 0,
                    reconcile_pending_total: 4,
                    reconcile_applied_total: 7,
                    reconcile_retry_later_total: 1,
                    reconcile_rejected_total: 0,
                    reconcile_unknown_total: 1,
                },
            ),
        ];
        for (_label, sample) in samples {
            let view = build_l2_l1_runtime_view(sample);
            let tripwire = build_l2_l1_tripwire_view(&view, true);
            l2_l1_runtime_fieldset_hard_gate(&tripwire);
            assert!(tripwire.strict);
            assert!(tripwire.consistent);
            assert!(tripwire.issue.is_empty());

            assert_eq!(view.versions.phase, L2_L1_EXPORT_BASELINE_PHASE);
            assert_eq!(
                view.versions.baseline_version,
                L2_L1_EXPORT_BASELINE_VERSION
            );
            assert_eq!(view.versions.lock_version, L2_L1_EXPORT_LOCK_VERSION);
            assert_eq!(
                view.versions.regression_lockset,
                L2_L1_EXPORT_REGRESSION_LOCKSET
            );
            assert_eq!(view.versions.fingerprint, L2_L1_EXPORT_FINGERPRINT);
            assert_eq!(
                view.versions.fieldset_version,
                L2_L1_EXPORT_FIELDSET_VERSION
            );
            assert_eq!(
                view.versions.fieldset_fingerprint,
                L2_L1_EXPORT_FIELDSET_FINGERPRINT
            );
            assert_eq!(view.versions.state_export_version, L2_STATE_EXPORT_VERSION);
            assert_eq!(
                view.versions.state_export_fingerprint,
                L2_STATE_EXPORT_FINGERPRINT
            );
            assert!(enforce_l2_l1_runtime_consistency_with_flag(&view, true).is_ok());
        }
    }

    #[test]
    fn l2_l1_runtime_strict_enforcement_accepts_consistent_view() {
        let view = build_l2_l1_runtime_view(L2RuntimeCounters::default());
        assert!(enforce_l2_l1_runtime_consistency_with_flag(&view, true).is_ok());
    }

    #[test]
    fn l2_l1_runtime_strict_enforcement_can_be_disabled() {
        let mut view = build_l2_l1_runtime_view(L2RuntimeCounters::default());
        view.versions.fieldset_version = view.versions.fieldset_version.saturating_add(1);
        assert!(enforce_l2_l1_runtime_consistency_with_flag(&view, false).is_ok());
        let err = enforce_l2_l1_runtime_consistency_with_flag(&view, true)
            .expect_err("strict mode should reject mismatch");
        assert!(err.to_string().contains("fieldset_version"));
    }

