    #[test]
    fn l1l4_anchor_record_cross_path_path_slots_do_not_alias_aggregate_seal_v1() {
        let snapshot = build_l2_state_snapshot(1, 2, 3, 4, 5, 6, 7, 8, 9);
        let record = build_anchor_record_for_l2_l1_mapping_test(snapshot);
        let json: serde_json::Value =
            serde_json::from_slice(&record.json_bytes).expect("parse L1/L4 anchor json");

        let aggregate = json["l2_l1_cross_path_seal_hash"]
            .as_u64()
            .expect("aggregate cross path seal hash must exist");
        let state = json["l2_l1_cross_path_state_seal_hash"]
            .as_u64()
            .expect("state cross path seal hash must exist");
        let replay = json["l2_l1_cross_path_replay_seal_hash"]
            .as_u64()
            .expect("replay cross path seal hash must exist");
        let watch = json["l2_l1_cross_path_watch_seal_hash"]
            .as_u64()
            .expect("watch cross path seal hash must exist");
        let batch = json["l2_l1_cross_path_batch_seal_hash"]
            .as_u64()
            .expect("batch cross path seal hash must exist");

        assert_ne!(state, aggregate, "state seal aliased aggregate seal");
        assert_ne!(replay, aggregate, "replay seal aliased aggregate seal");
        assert_ne!(watch, aggregate, "watch seal aliased aggregate seal");
        assert_ne!(batch, aggregate, "batch seal aliased aggregate seal");
        assert_eq!(state, 1001, "state seal test slot drift");
        assert_eq!(replay, 1002, "replay seal test slot drift");
        assert_eq!(watch, 1003, "watch seal test slot drift");
        assert_eq!(batch, 1004, "batch seal test slot drift");
    }

