    #[test]
    fn l2_l1_runtime_fieldset_lock_is_stable() {
        assert_eq!(L2_L1_RUNTIME_FIELDSET_VERSION, 6);
        assert_eq!(
            L2_L1_RUNTIME_FIELDSET_FINGERPRINT,
            "l2-l1-runtime-fieldset:v6:l2_l1_export_*+l2_l1_tripwire_*+l2_l1_tripwire_strict_governance_*+l2_l1_contract_*+l2_l1_closure_*+l2_l1_governance_*+l2_l1_cross_path_*+l2_l1_baseline_seal_*+l2_state_export_*+l2_*"
        );
        assert_eq!(L2_L1_RUNTIME_FIELDSET.len(), 38);
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_tripwire_strict"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_tripwire_strict_source"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_tripwire_strict_requested"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_tripwire_strict_switch_semantics"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_tripwire_consistent"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_tripwire_issue"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_contract_version"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_contract_fingerprint"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_closure_seal_version"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_closure_seal_fingerprint"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_closure_seal_hash"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_governance_lock_version"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_governance_lock_fingerprint"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_governance_lock_hash"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_cross_path_lock_version"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_cross_path_fingerprint"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_cross_path_seal_hash"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_baseline_seal_version"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_baseline_seal_fingerprint"));
        assert!(L2_L1_RUNTIME_FIELDSET.contains(&"l2_l1_baseline_seal_hash"));
        assert_eq!(L2_L1_STATE_ANCHOR_MIRROR_FIELDSET_VERSION, 6);
        assert_eq!(
            L2_L1_STATE_ANCHOR_MIRROR_FIELDSET_FINGERPRINT,
            "l2-l1-state-anchor-mirror:v6:runtime-fieldset+tripwire-governance+closure-seal+governance-lock+cross-path-seal+baseline-seal"
        );
        assert_eq!(L2_L1_STATE_ANCHOR_MIRROR_FIELDSET, L2_L1_RUNTIME_FIELDSET);
        assert_eq!(L2_L1_CONTRACT_VERSION, 6);
        assert_eq!(
            L2_L1_CONTRACT_FINGERPRINT,
            "l2-l1-contract:v6:runtime+state+anchor-single-source+tripwire-governance+closure-seal+governance-lock+cross-path-seal+baseline-seal"
        );
        assert_eq!(L2_L1_CONTRACT_COMPAT_VERSION, 1);
        assert_eq!(L2_L1_CONTRACT_BREAKING_GUARD_VERSION, 1);
        assert_eq!(
            L2_L1_CONTRACT_BREAKING_GUARD_FINGERPRINT,
            "l2-l1-contract-breaking-guard:v1:contract+fieldset+path-lock"
        );
        assert_eq!(L2_L1_GOVERNANCE_LOCK_VERSION, 1);
        assert_eq!(
            L2_L1_GOVERNANCE_LOCK_FINGERPRINT,
            "l2-l1-governance-lock:v1:l3-profile-governance+tripwire-strict-governance+l2-export-mode"
        );
        assert_eq!(L2_L1_CROSS_PATH_LOCK_VERSION, 1);
        assert_eq!(
            L2_L1_CROSS_PATH_REGRESSION_LOCKSET,
            L2_L1_EXPORT_REGRESSION_LOCKSET
        );
        assert_eq!(
            L2_L1_CROSS_PATH_FINGERPRINT,
            "l2-l1-cross-path-lock:v1:tripwire+contract+governance"
        );
        assert_eq!(L2_L1_BASELINE_SEAL_VERSION, 1);
        assert_eq!(
            L2_L1_BASELINE_SEAL_FINGERPRINT,
            "l2-l1-baseline-seal:v1:export-mode+governance+cross-path"
        );
        assert_eq!(L2_L1_CLOSURE_SEAL_VERSION, 1);
        assert_eq!(
            L2_L1_CLOSURE_SEAL_FINGERPRINT,
            "l2-l1-closure-seal:v1:runtime+tripwire+state"
        );
        assert_eq!(L2_L1_CONTRACT_FIELDSET, L2_L1_RUNTIME_FIELDSET);
        assert_eq!(L2_L1_STATE_LOG_FIELDSET_VERSION, 6);
        assert_eq!(
            L2_L1_STATE_LOG_FIELDSET_FINGERPRINT,
            "l2-l1-state-log:v6:state-anchor-mirror-fieldset+tripwire-governance+closure-seal+governance-lock+cross-path-seal+baseline-seal"
        );
        assert_eq!(L2_L1_STATE_LOG_FIELDSET, L2_L1_STATE_ANCHOR_MIRROR_FIELDSET);
        assert_eq!(L2_L1_PATH_LOCK_VERSION, 1);
        assert_eq!(
            L2_L1_PATH_REGRESSION_LOCKSET,
            L2_L1_EXPORT_REGRESSION_LOCKSET
        );
        assert_eq!(
            L2_L1_PATH_FINGERPRINT,
            "l2-l1-path-lock:v1:state+watch+batch"
        );
        assert_eq!(L2_L1_EXPORT_CURRENT_VERSION, 2);
        assert_eq!(L2_L1_EXPORT_COMPAT_VERSION, 1);
        assert_eq!(L2_L1_EXPORT_COMPAT_LOCKSET, L2_L1_EXPORT_REGRESSION_LOCKSET);
        assert_eq!(
            L2_L1_EXPORT_COMPAT_FINGERPRINT,
            "l2-l1-export-compat:v1:legacy-anchor-fieldset"
        );
    }

