    #[test]
    fn l2_l1_path_lock_accepts_state_watch_batch_and_is_deterministic() {
        let runtime = build_l2_l1_runtime_view(L2RuntimeCounters {
            queue_total: 9,
            replay_applied_total: 4,
            replay_retry_later_total: 1,
            replay_rejected_total: 0,
            reconcile_pending_total: 3,
            reconcile_applied_total: 4,
            reconcile_retry_later_total: 1,
            reconcile_rejected_total: 0,
            reconcile_unknown_total: 0,
        });
        let tripwire = build_l2_l1_tripwire_view(&runtime, true);
        let state = l2_l1_path_consistency_hard_gate("state", &runtime, &tripwire);
        let watch = l2_l1_path_consistency_hard_gate("watch", &runtime, &tripwire);
        let batch = l2_l1_path_consistency_hard_gate("batch", &runtime, &tripwire);
        assert_eq!(state.lock_version, L2_L1_PATH_LOCK_VERSION);
        assert_eq!(state.regression_lockset, L2_L1_PATH_REGRESSION_LOCKSET);
        assert_eq!(state.fingerprint, L2_L1_PATH_FINGERPRINT);
        assert_eq!(state.path, "state");
        assert_eq!(watch.path, "watch");
        assert_eq!(batch.path, "batch");
        assert_eq!(state.closure_seal_hash, watch.closure_seal_hash);
        assert_eq!(watch.closure_seal_hash, batch.closure_seal_hash);
        assert_ne!(state.seal_hash, watch.seal_hash);
        assert_ne!(watch.seal_hash, batch.seal_hash);
        assert_ne!(state.seal_hash, batch.seal_hash);
    }

    #[test]
    fn l2_l1_path_lock_rejects_invalid_path_label() {
        let runtime = build_l2_l1_runtime_view(L2RuntimeCounters {
            queue_total: 9,
            replay_applied_total: 4,
            replay_retry_later_total: 1,
            replay_rejected_total: 0,
            reconcile_pending_total: 3,
            reconcile_applied_total: 4,
            reconcile_retry_later_total: 1,
            reconcile_rejected_total: 0,
            reconcile_unknown_total: 0,
        });
        let tripwire = build_l2_l1_tripwire_view(&runtime, true);
        let panicked = std::panic::catch_unwind(|| {
            let _ = l2_l1_path_consistency_hard_gate("invalid-path", &runtime, &tripwire);
        })
        .is_err();
        assert!(panicked, "path lock must reject invalid path label");
    }

