        assert_triplet_ascending(tripwire_baseline, "tripwire baseline");
        assert_triplet_ascending(tripwire_closure, "tripwire closure");
        assert_triplet_ascending(summary_baseline, "cross_path_summary baseline");
        assert_triplet_ascending(summary_closure, "cross_path_summary closure");
