    #[test]
    fn l2_l1_cross_path_seal_family_group_order_is_aligned_across_exports_v1() {
        fn index_of(tokens: &[&str], key: &str) -> usize {
            tokens
                .iter()
                .position(|t| t.starts_with(key))
                .unwrap_or_else(|| panic!("template missing key token: {key}"))
        }

        fn assert_group_order(
            tokens: &[&str],
            baseline_prefix: &str,
            closure_prefix: &str,
            label: &str,
        ) {
            let b_ver = index_of(
                tokens,
                &format!("{baseline_prefix}baseline_seal_version={{}}"),
            );
            let b_fpr = index_of(
                tokens,
                &format!("{baseline_prefix}baseline_seal_fingerprint={{}}"),
            );
            let b_hash = index_of(tokens, &format!("{baseline_prefix}baseline_seal_hash={{}}"));
            let c_ver = index_of(
                tokens,
                &format!("{closure_prefix}closure_seal_version={{}}"),
            );
            let c_fpr = index_of(
                tokens,
                &format!("{closure_prefix}closure_seal_fingerprint={{}}"),
            );
            let c_hash = index_of(tokens, &format!("{closure_prefix}closure_seal_hash={{}}"));

            assert!(
                b_ver < b_fpr
                    && b_fpr < b_hash
                    && b_hash < c_ver
                    && c_ver < c_fpr
                    && c_fpr < c_hash,
                "{label} seal family group order drift detected"
            );
        }

        let source = include_str!(concat!(
            env!("CARGO_MANIFEST_DIR"),
            "/src/bin/novovm-node.rs"
        ));

        let state_line = source
            .lines()
            .find(|l| {
                l.contains("\"availability_state: pending=")
                    && l.contains("l2_l1_cross_path_lock_version={}")
            })
            .expect("availability_state template line must exist");
        let tripwire_line = source
            .lines()
            .find(|l| {
                l.contains("\"availability_l2_l1_tripwire: ")
                    && l.contains("strict={}")
                    && l.contains("consistent={}")
                    && l.contains("cross_path_state_seal_hash={}")
            })
            .expect("availability_l2_l1_tripwire template line must exist");
        let summary_line = source
            .lines()
            .find(|l| {
                l.contains("\"availability_l2_l1_cross_path_summary: ")
                    && l.contains("lock_version={}")
                    && l.contains("regression_lockset={}")
            })
            .expect("availability_l2_l1_cross_path_summary template line must exist");

        let state_tokens: Vec<&str> = state_line.split_whitespace().collect();
        let tripwire_tokens: Vec<&str> = tripwire_line.split_whitespace().collect();
        let summary_tokens: Vec<&str> = summary_line.split_whitespace().collect();

        assert_group_order(&state_tokens, "l2_l1_", "l2_l1_", "availability_state");
        assert_group_order(&tripwire_tokens, "", "", "availability_l2_l1_tripwire");
        assert_group_order(
            &summary_tokens,
            "",
            "",
            "availability_l2_l1_cross_path_summary",
        );
    }

