    #[test]
    fn l2_l1_cross_path_summary_namespace_remains_export_facing_v1() {
        fn extract_keys(line: &str) -> Vec<String> {
            line.split_whitespace()
                .filter_map(|t| {
                    let tok = t.trim_end_matches(',').trim_end_matches('"');
                    tok.split_once("={}").map(|(k, _)| k.to_string())
                })
                .collect()
        }

        let source = include_str!(concat!(
            env!("CARGO_MANIFEST_DIR"),
            "/src/bin/novovm-node.rs"
        ));
        let summary_templates: Vec<&str> = source
            .lines()
            .filter(|l| {
                l.contains("\"availability_l2_l1_cross_path_summary: ")
                    && l.contains("lock_version={}")
                    && l.contains("regression_lockset={}")
                    && l.contains("fingerprint={}")
                    && l.contains("state={}")
                    && l.contains("replay={}")
                    && l.contains("watch={}")
                    && l.contains("batch={}")
            })
            .collect();

        assert_eq!(
            summary_templates.len(),
            3,
            "cross path summary templates must include exactly state/watch/batch variants"
        );

        for line in summary_templates {
            let keys = extract_keys(line);
            assert!(
                keys.iter().all(|k| !k.starts_with("l2_l1_")),
                "cross_path_summary must remain export-facing namespace without l2_l1_* keys"
            );
        }
    }

