    #[test]
    fn l2_l1_cross_path_seal_fanout_keyset_is_exactly_aligned_v1() {
        fn count_prefixed(tokens: &[&str], key: &str) -> usize {
            tokens.iter().filter(|t| t.starts_with(key)).count()
        }

        let source = include_str!(concat!(
            env!("CARGO_MANIFEST_DIR"),
            "/src/bin/novovm-node.rs"
        ));
        let state_line = source
            .lines()
            .find(|l| {
                l.contains("\"availability_state: pending=")
                    && l.contains("l2_l1_cross_path_seal_hash={}")
                    && l.contains("l2_l1_cross_path_batch_seal_hash={}")
            })
            .expect("availability_state template line must exist");
        let tripwire_line = source
            .lines()
            .find(|l| {
                l.contains("\"availability_l2_l1_tripwire: ")
                    && l.contains("cross_path_seal_hash={}")
                    && l.contains("cross_path_batch_seal_hash={}")
            })
            .expect("availability_l2_l1_tripwire template line must exist");

        let state_tokens: Vec<&str> = state_line.split_whitespace().collect();
        let tripwire_tokens: Vec<&str> = tripwire_line.split_whitespace().collect();

        let state_expected = [
            "l2_l1_cross_path_seal_hash={}",
            "l2_l1_cross_path_state_seal_hash={}",
            "l2_l1_cross_path_replay_seal_hash={}",
            "l2_l1_cross_path_watch_seal_hash={}",
            "l2_l1_cross_path_batch_seal_hash={}",
        ];
        let tripwire_expected = [
            "cross_path_seal_hash={}",
            "cross_path_state_seal_hash={}",
            "cross_path_replay_seal_hash={}",
            "cross_path_watch_seal_hash={}",
            "cross_path_batch_seal_hash={}",
        ];

        for key in state_expected {
            assert_eq!(
                count_prefixed(&state_tokens, key),
                1,
                "availability_state cross-path seal fanout key multiplicity drift: {key}"
            );
        }
        for key in tripwire_expected {
            assert_eq!(
                count_prefixed(&tripwire_tokens, key),
                1,
                "availability_l2_l1_tripwire cross-path seal fanout key multiplicity drift: {key}"
            );
        }

        let state_cross_path_seal_count = state_tokens
            .iter()
            .filter(|t| t.starts_with("l2_l1_cross_path_") && t.contains("seal_hash={}"))
            .count();
        let tripwire_cross_path_seal_count = tripwire_tokens
            .iter()
            .filter(|t| t.starts_with("cross_path_") && t.contains("seal_hash={}"))
            .count();

        assert_eq!(
            state_cross_path_seal_count, 5,
            "availability_state cross-path seal fanout keyset size drift detected"
        );
        assert_eq!(
            tripwire_cross_path_seal_count, 5,
            "availability_l2_l1_tripwire cross-path seal fanout keyset size drift detected"
        );
    }

