    #[test]
    fn l2_l1_cross_path_gate_key_multiplicity_and_path_block_order_is_locked_v1() {
        fn count_prefixed(tokens: &[&str], key: &str) -> usize {
            tokens.iter().filter(|t| t.starts_with(key)).count()
        }

        fn index_of(tokens: &[&str], key: &str) -> usize {
            tokens
                .iter()
                .position(|t| t.starts_with(key))
                .unwrap_or_else(|| panic!("cross_path_gate template missing key token: {key}"))
        }

        let source = include_str!(concat!(
            env!("CARGO_MANIFEST_DIR"),
            "/src/bin/novovm-node.rs"
        ));
        let gate_lines: Vec<&str> = source
            .lines()
            .filter(|l| {
                l.contains("\"availability_l2_l1_cross_path_gate: path=")
                    && l.contains("lock_version={}")
                    && l.contains("regression_lockset={}")
                    && l.contains("fingerprint={}")
                    && l.contains("seal_hash={}")
            })
            .collect();

        assert_eq!(
            gate_lines.len(),
            2,
            "cross_path_gate template count drift detected"
        );

        let expected_once = [
            "path=",
            "scope=",
            "lock_version={}",
            "regression_lockset={}",
            "fingerprint={}",
            "seal_hash={}",
        ];

        for line in gate_lines {
            let tokens: Vec<&str> = line.split_whitespace().collect();
            for key in expected_once {
                assert_eq!(
                    count_prefixed(&tokens, key),
                    1,
                    "cross_path_gate key multiplicity drift detected for {key}"
                );
            }

            let path_block = [
                index_of(&tokens, "path="),
                index_of(&tokens, "scope="),
                index_of(&tokens, "lock_version={}"),
                index_of(&tokens, "regression_lockset={}"),
                index_of(&tokens, "fingerprint={}"),
                index_of(&tokens, "seal_hash={}"),
            ];

            assert!(
                path_block.windows(2).all(|w| w[0] < w[1]),
                "cross_path_gate path block order drift detected"
            );
            assert!(
                path_block.windows(2).all(|w| w[1] == w[0] + 1),
                "cross_path_gate path block contiguity drift detected"
            );
        }
    }

