    #[test]
    fn l2_l1_cross_path_gate_templates_have_identical_keyset_and_order_v1() {
        fn normalize_gate_keys(line: &str) -> Vec<String> {
            line.split_whitespace()
                .filter_map(|t| {
                    if t.starts_with("path=") {
                        Some("path=".to_string())
                    } else if t.starts_with("scope=") {
                        Some("scope=".to_string())
                    } else if t.starts_with("lock_version={}") {
                        Some("lock_version={}".to_string())
                    } else if t.starts_with("regression_lockset={}") {
                        Some("regression_lockset={}".to_string())
                    } else if t.starts_with("fingerprint={}") {
                        Some("fingerprint={}".to_string())
                    } else if t.starts_with("seal_hash={}") {
                        Some("seal_hash={}".to_string())
                    } else {
                        None
                    }
                })
                .collect()
        }

        let source = include_str!(concat!(
            env!("CARGO_MANIFEST_DIR"),
            "/src/bin/novovm-node.rs"
        ));
        let gate_lines: Vec<&str> = source
            .lines()
            .filter(|l| {
                l.contains("\"availability_l2_l1_cross_path_gate: path=")
                    && l.contains("lock_version={}")
                    && l.contains("regression_lockset={}")
                    && l.contains("fingerprint={}")
                    && l.contains("seal_hash={}")
            })
            .collect();

        assert_eq!(
            gate_lines.len(),
            2,
            "cross_path_gate template count drift detected"
        );

        let watch_line = gate_lines
            .iter()
            .find(|l| l.contains("path=watch"))
            .expect("watch cross_path_gate template must exist");
        let batch_line = gate_lines
            .iter()
            .find(|l| l.contains("path=batch"))
            .expect("batch cross_path_gate template must exist");

        let watch_keys = normalize_gate_keys(watch_line);
        let batch_keys = normalize_gate_keys(batch_line);

        assert_eq!(
            watch_keys, batch_keys,
            "cross_path_gate watch/batch keyset or key-order drift detected"
        );
        assert_eq!(
            watch_keys,
            vec![
                "path=".to_string(),
                "scope=".to_string(),
                "lock_version={}".to_string(),
                "regression_lockset={}".to_string(),
                "fingerprint={}".to_string(),
                "seal_hash={}".to_string(),
            ],
            "cross_path_gate key order baseline drift detected"
        );

        for forbidden in [
            "path_lock_version={}",
            "path_regression_lockset={}",
            "path_fingerprint={}",
            "path_seal_hash={}",
            "state_export_version={}",
        ] {
            assert!(
                !watch_line.contains(forbidden) && !batch_line.contains(forbidden),
                "cross_path_gate template leaked internal alias key: {forbidden}"
            );
        }
    }

