    #[test]
    fn l2_l1_cross_path_gate_path_scope_tokens_are_sanitized_v1() {
        fn token_value<'a>(line: &'a str, prefix: &str) -> &'a str {
            line.split_whitespace()
                .find_map(|t| t.strip_prefix(prefix))
                .unwrap_or_else(|| {
                    panic!("cross_path_gate template missing token prefix: {prefix}")
                })
        }

        let source = include_str!(concat!(
            env!("CARGO_MANIFEST_DIR"),
            "/src/bin/novovm-node.rs"
        ));
        let gate_lines: Vec<&str> = source
            .lines()
            .filter(|l| {
                l.contains("\"availability_l2_l1_cross_path_gate: path=")
                    && l.contains("lock_version={}")
                    && l.contains("regression_lockset={}")
                    && l.contains("fingerprint={}")
                    && l.contains("seal_hash={}")
            })
            .collect();

        assert_eq!(
            gate_lines.len(),
            2,
            "cross_path_gate template count drift detected"
        );

        for line in gate_lines {
            let path = token_value(line, "path=");
            let scope = token_value(line, "scope=");
            assert!(
                path.chars().all(|c| c.is_ascii_lowercase()),
                "cross_path_gate path token sanitation drift detected: {path}"
            );
            assert!(
                !path.contains(',') && !path.contains('\"'),
                "cross_path_gate path token must not carry punctuation: {path}"
            );
            assert!(
                !scope.contains(',') && !scope.contains('\"'),
                "cross_path_gate scope token must not carry punctuation: {scope}"
            );
            assert!(
                scope.starts_with("state+replay+"),
                "cross_path_gate scope prefix drift detected: {scope}"
            );
        }
    }

