    #[test]
    fn availability_state_export_lockset_slots_keep_stable_relative_order_v1() {
        fn index_of(tokens: &[&str], key: &str) -> usize {
            tokens
                .iter()
                .position(|t| *t == key)
                .unwrap_or_else(|| panic!("availability_state template missing key token: {key}"))
        }

        let source = include_str!(concat!(
            env!("CARGO_MANIFEST_DIR"),
            "/src/bin/novovm-node.rs"
        ));
        let line = source
            .lines()
            .find(|l| {
                l.contains("\"availability_state: pending=")
                    && l.contains("l2_l1_export_regression_lockset={}")
                    && l.contains("l2_state_export_fingerprint={}")
            })
            .expect("availability_state template line must exist");
        let tokens: Vec<&str> = line.split_whitespace().collect();

        let i0 = index_of(&tokens, "l2_l1_export_lock_version={}");
        let i1 = index_of(&tokens, "l2_l1_export_regression_lockset={}");
        let i2 = index_of(&tokens, "l2_l1_export_fingerprint={}");
        let i3 = index_of(&tokens, "l2_l1_export_fieldset_version={}");
        let i4 = index_of(&tokens, "l2_l1_export_fieldset_fingerprint={}");
        let i5 = index_of(&tokens, "l2_state_export_version={}");
        let i6 = index_of(&tokens, "l2_state_export_fingerprint={}");

        assert!(
            i0 < i1 && i1 < i2 && i2 < i3 && i3 < i4 && i4 < i5 && i5 < i6,
            "availability_state export lockset slot order drift detected"
        );
    }

