fn l2_l1_runtime_fieldset_hard_gate(tripwire: &L2L1TripwireView) {
    l2_l1_contract_hard_gate();
    l2_l1_state_anchor_mirror_fieldset_hard_gate();
    l2_l1_state_log_fieldset_hard_gate();
    debug_assert_eq!(L2_L1_RUNTIME_FIELDSET_VERSION, 6);
    debug_assert_eq!(L2_L1_RUNTIME_FIELDSET.len(), 38);
    debug_assert_eq!(
        L2_L1_RUNTIME_FIELDSET_FINGERPRINT,
        "l2-l1-runtime-fieldset:v6:l2_l1_export_*+l2_l1_tripwire_*+l2_l1_tripwire_strict_governance_*+l2_l1_contract_*+l2_l1_closure_*+l2_l1_governance_*+l2_l1_cross_path_*+l2_l1_baseline_seal_*+l2_state_export_*+l2_*"
    );
    if tripwire.consistent {
        debug_assert!(tripwire.issue.is_empty());
    }
}

fn l2_l1_contract_hard_gate() {
    l2_l1_export_dual_version_hard_gate();
    debug_assert_eq!(L2_L1_CONTRACT_VERSION, 6);
    debug_assert_eq!(
        L2_L1_CONTRACT_FINGERPRINT,
        "l2-l1-contract:v6:runtime+state+anchor-single-source+tripwire-governance+closure-seal+governance-lock+cross-path-seal+baseline-seal"
    );
    debug_assert_eq!(L2_L1_CONTRACT_COMPAT_VERSION, 1);
    debug_assert_eq!(L2_L1_CONTRACT_BREAKING_GUARD_VERSION, 1);
    debug_assert_eq!(
        L2_L1_CONTRACT_BREAKING_GUARD_FINGERPRINT,
        "l2-l1-contract-breaking-guard:v1:contract+fieldset+path-lock"
    );
    debug_assert_eq!(L2_L1_GOVERNANCE_LOCK_VERSION, 1);
    debug_assert_eq!(
        L2_L1_GOVERNANCE_LOCK_FINGERPRINT,
        "l2-l1-governance-lock:v1:l3-profile-governance+tripwire-strict-governance+l2-export-mode"
    );
    debug_assert_eq!(L2_L1_CROSS_PATH_LOCK_VERSION, 1);
    debug_assert_eq!(
        L2_L1_CROSS_PATH_REGRESSION_LOCKSET,
        L2_L1_PATH_REGRESSION_LOCKSET
    );
    debug_assert_eq!(
        L2_L1_CROSS_PATH_FINGERPRINT,
        "l2-l1-cross-path-lock:v1:tripwire+contract+governance"
    );
    debug_assert_eq!(L2_L1_BASELINE_SEAL_VERSION, 1);
    debug_assert_eq!(
        L2_L1_BASELINE_SEAL_FINGERPRINT,
        "l2-l1-baseline-seal:v1:export-mode+governance+cross-path"
    );
    debug_assert_eq!(L2_L1_CLOSURE_SEAL_VERSION, 1);
    debug_assert_eq!(
        L2_L1_CLOSURE_SEAL_FINGERPRINT,
        "l2-l1-closure-seal:v1:runtime+tripwire+state"
    );
    debug_assert_eq!(L2_L1_CONTRACT_FIELDSET, L2_L1_RUNTIME_FIELDSET);
    debug_assert_eq!(L2_L1_CONTRACT_FIELDSET, L2_L1_STATE_ANCHOR_MIRROR_FIELDSET);
    debug_assert_eq!(L2_L1_CONTRACT_FIELDSET, L2_L1_STATE_LOG_FIELDSET);
    debug_assert_ne!(l2_l1_contract_breaking_guard_hash(), 0);
}

fn l2_l1_state_anchor_mirror_fieldset_hard_gate() {
    debug_assert_eq!(L2_L1_STATE_ANCHOR_MIRROR_FIELDSET_VERSION, 6);
    debug_assert_eq!(
        L2_L1_STATE_ANCHOR_MIRROR_FIELDSET_FINGERPRINT,
        "l2-l1-state-anchor-mirror:v6:runtime-fieldset+tripwire-governance+closure-seal+governance-lock+cross-path-seal+baseline-seal"
    );
    debug_assert_eq!(L2_L1_STATE_ANCHOR_MIRROR_FIELDSET, L2_L1_RUNTIME_FIELDSET);
}

fn l2_l1_state_log_fieldset_hard_gate() {
    debug_assert_eq!(L2_L1_STATE_LOG_FIELDSET_VERSION, 6);
    debug_assert_eq!(
        L2_L1_STATE_LOG_FIELDSET_FINGERPRINT,
        "l2-l1-state-log:v6:state-anchor-mirror-fieldset+tripwire-governance+closure-seal+governance-lock+cross-path-seal+baseline-seal"
    );
    debug_assert_eq!(L2_L1_STATE_LOG_FIELDSET, L2_L1_STATE_ANCHOR_MIRROR_FIELDSET);
}

fn enforce_l2_l1_runtime_consistency_with_flag(view: &L2L1RuntimeView, strict: bool) -> Result<()> {
    let tripwire = build_l2_l1_tripwire_view(view, strict);
    if tripwire.strict && !tripwire.consistent {
        bail!(
            "l2/l1 runtime consistency tripwire violated: {}",
            tripwire.issue
        );
    }
    Ok(())
}

fn l2_l1_tripwire_strict_governance_from_raw_input(
    requested_raw: Option<&str>,
) -> L2L1TripwireStrictGovernanceView {
    match requested_raw {
        Some(raw) => {
            let requested = raw.trim().to_string();
            match requested.to_ascii_lowercase().as_str() {
                "1" | "true" | "yes" | "on" => L2L1TripwireStrictGovernanceView {
                    effective_strict: true,
                    requested_mode: requested,
                    source: "env_explicit",
                    switch_semantics: L2_L1_TRIPWIRE_STRICT_SWITCH_SEMANTICS,
                },
                "0" | "false" | "no" | "off" => L2L1TripwireStrictGovernanceView {
                    effective_strict: false,
                    requested_mode: requested,
                    source: "env_explicit",
                    switch_semantics: L2_L1_TRIPWIRE_STRICT_SWITCH_SEMANTICS,
                },
                _ => L2L1TripwireStrictGovernanceView {
                    effective_strict: true,
                    requested_mode: requested,
                    source: "env_invalid_fallback",
                    switch_semantics: L2_L1_TRIPWIRE_STRICT_SWITCH_SEMANTICS,
                },
            }
        }
        None => L2L1TripwireStrictGovernanceView {
            effective_strict: true,
            requested_mode: "-".to_string(),
            source: "default_true",
            switch_semantics: L2_L1_TRIPWIRE_STRICT_SWITCH_SEMANTICS,
        },
    }
}

fn resolve_l2_l1_tripwire_strict_governance_from_env() -> L2L1TripwireStrictGovernanceView {
    let requested = std::env::var("NOVOVM_L2_L1_RUNTIME_TRIPWIRE_STRICT").ok();
    l2_l1_tripwire_strict_governance_from_raw_input(requested.as_deref())
}

